import React from 'react';
import { Link } from 'react-router-dom';

const Footer = () => {
    const currentYear = new Date().getFullYear();

    return (
        <footer style={styles.footerContainer}>
            <div style={styles.contentWrapper}>
                {/* Texto de Copyright principal */}
                <p style={styles.copyrightText}>
                    © {currentYear}  Bicentenario de Bolivia. Todos los derechos reservados.
                    {/* Eliminado "Trinity Team" */}
                </p>

                {/* Contenido de las 3 columnas */}
                <div style={styles.mainContentGrid}>

                    {/* Columna 1: Navegación */}
                    <div style={styles.gridColumn}>
                        <h3 style={styles.sectionTitle}>NAVEGACIÓN</h3>
                        <ul style={styles.linkList}>
                            <li><Link to="/" style={styles.link}>Inicio</Link></li>
                            <li><Link to="/login" style={styles.link}>Login</Link></li>
                            <li><Link to="/register" style={styles.link}>Registro</Link></li>
                        </ul>
                    </div>

                    {/* Columna 2: Redes Sociales */}
                    <div style={styles.gridColumn}>
                        <h3 style={styles.sectionTitle}>REDES SOCIALES</h3>
                        <div style={styles.socialIcons}>
                            {/* **IMPORTANTE:** Asegúrate de que estos archivos PNG existan en public/media/icons/ */}
                            {/* Si no tienes estas imágenes, los íconos no se mostrarán. */}
                            <a href="https://www.facebook.com/TuPaginaDeFacebook" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
                                <img src="/media/icons/facebook_icon.png" alt="Facebook" style={styles.socialIconImage} />
                            </a>
                            <a href="https://www.instagram.com/TuCuentaDeInstagram" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
                                <img src="/media/icons/instagram_icon.png" alt="Instagram" style={styles.socialIconImage} />
                            </a>
                            <a href="https://www.tiktok.com/@TuCuentaDeTikTok" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
                                <img src="/media/icons/tiktok_icon.png" alt="TikTok" style={styles.socialIconImage} />
                            </a>
                        </div>
                    </div>

                    {/* Columna 3: Sobre el Repositorio */}
                    <div style={styles.gridColumn}>
                        <h3 style={styles.sectionTitle}>SOBRE EL REPOSITORIO</h3>
                        <p style={styles.aboutText}>
                            Plataforma digital para consulta, preservación y análisis de documentos históricos bolivianos. Proyecto del Bicentenario 2025.
                        </p>
                    </div>
                </div>

                {/* Línea divisoria */}
                <div style={styles.divider}></div>

                {/* Cita final y Crédito de Alberto Navarro */}
                <p style={styles.quoteText}>
                    “Conocer nuestra historia es entender nuestro presente.”
                </p>
                <p style={styles.navarroCredit}>Desarrollado por Alberto Navarro</p>

            </div>
        </footer>
    );
};

const styles = {
    footerContainer: {
        // IMAGEN DE FONDO: Asegúrate de que footer2.png está en public/media/
        backgroundImage: "url('/media/footer2.png')", //
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        backgroundRepeat: 'no-repeat',
        backgroundColor: '#F8F6F1', // Un beige suave de respaldo
        color: '#4a4a4a', // Color de texto principal
        fontFamily: "'Inter', sans-serif", // Fuente similar a la de Tailwind
        padding: '15px 0', // Padding vertical MUCHO MENOR para reducir la altura
        marginTop: 'auto', // Para que se pegue al final de la página
        boxShadow: '0 -2px 8px rgba(0,0,0,0.02)', // Sombra muy sutil
        fontSize: '0.8rem', // Tamaño de fuente general más pequeño
        lineHeight: '1.4',
        minHeight: '180px', // Altura mínima para que no sea *demasiado* pequeño
        display: 'flex', // Para que el contenido se centre verticalmente si es necesario
        alignItems: 'center', // Centra el contenido verticalmente
    },
    contentWrapper: {
        maxWidth: '900px', // Ancho máximo ligeramente menor para compactar
        margin: '0 auto',
        padding: '0 15px', // Padding horizontal
        textAlign: 'center',
        width: '100%', // Asegura que ocupe el ancho disponible
    },
    copyrightText: {
        fontSize: '0.75rem', // Más pequeño que antes
        color: '#555',
        marginBottom: '15px', // Espacio abajo del copyright
        textAlign: 'center',
        fontWeight: 'normal',
    },
    teamName: {
        fontWeight: 'bold', // Solo el nombre del equipo en negrita
        color: '#333',
    },
    mainContentGrid: {
        display: 'flex',
        flexWrap: 'wrap', // Permite que las columnas bajen en pantallas pequeñas
        justifyContent: 'space-around', // Distribuye las columnas
        gap: '20px', // Espacio entre las columnas
        marginBottom: '15px', // Espacio entre las columnas y la línea divisoria
    },
    section: {
        flex: '1 1 200px', // Cada columna intenta ocupar al menos 200px, si no hay espacio, se envuelven
        minWidth: '150px', // Ancho mínimo para evitar compresión excesiva
        padding: '0 5px', // Padding interno para cada sección
        textAlign: 'center', // Centrado para todas las secciones
    },
    sectionTitle: {
        fontSize: '0.85rem', // Títulos más pequeños
        fontWeight: 'bold',
        marginBottom: '8px', // Menos margen abajo del título
        textTransform: 'uppercase',
        color: '#222',
    },
    linkList: {
        listStyle: 'none',
        padding: 0,
        margin: 0,
        lineHeight: '1.2', // Reduce el espaciado entre ítems de la lista
    },
    link: {
        textDecoration: 'none',
        color: '#555',
        fontSize: '0.8rem', // Tamaño de fuente para enlaces más pequeño
        transition: 'color 0.2s ease',
        display: 'inline-block',
        '&:hover': {
            color: '#1e7e34', // Un verde
        },
    },
    socialIcons: {
        display: 'flex',
        justifyContent: 'center', // Centrar los íconos
        gap: '10px', // Espacio entre los íconos
        marginTop: '5px',
    },
    socialIconLink: {
        textDecoration: 'none',
        display: 'inline-block',
    },
    socialIconImage: {
        width: '18px', // Íconos aún más pequeños para un look compacto
        height: '18px',
        opacity: 0.8,
        transition: 'opacity 0.2s ease, transform 0.1s ease',
        '&:hover': {
            opacity: 1,
            transform: 'scale(1.1)',
        },
    },
    aboutText: {
        fontSize: '0.75rem', // Texto de descripción más pequeño
        color: '#666',
        lineHeight: '1.3',
        margin: 0,
    },
    divider: {
        borderBottom: '1px solid rgba(200,200,200,0.4)', // Línea divisoria sutil
        width: '80%', // Ancho de la línea
        margin: '0 auto 10px auto', // Centrar y espacio
    },
    quoteText: {
        fontSize: '0.7rem', // Tamaño de fuente para la cita muy pequeña
        fontStyle: 'italic',
        color: '#777',
        margin: '0 0 5px 0', // Menos margen
        textAlign: 'center',
    },
    navarroCredit: {
        fontSize: '0.6rem', // Muy pequeño, un detalle discreto
        color: '#888',
        marginTop: '0', // Sin margen superior extra
        textAlign: 'center',
    }
};

export default Footer;
